function preloadFunction () {
    const preloadEl = document.querySelector('body .preload')
    const stateEl = document.querySelector('body .state')
    const mouseEl = document.querySelector('body .mouse')
    
    mouseEl.style.animation = "mouseWidthAnimated 1s infinite"
    preloadEl.style.display = 'none';
    stateEl.style.display = 'flex';


}